<?php

declare(strict_types=1);

use Symfony\Component\Config\Definition\Configurator\DefinitionConfigurator;

return static function (DefinitionConfigurator $definition): void {
    $definition->rootNode()
        ->children()
            ->booleanNode('enabled')
                ->defaultTrue()
            ->end()
            ->floatNode('budget_warning')
                ->defaultNull()
                ->min(0)
                ->info('Per-request budget threshold. Toolbar turns red when exceeded.')
            ->end()
            ->arrayNode('cost_thresholds')
                ->addDefaultsIfNotSet()
                ->children()
                    ->floatNode('low')
                        ->defaultValue(0.01)
                        ->min(0)
                        ->info('Costs below this threshold are shown in green.')
                    ->end()
                    ->floatNode('medium')
                        ->defaultValue(0.10)
                        ->min(0)
                        ->info('Costs between low and medium are shown in yellow. Above medium is red.')
                    ->end()
                ->end()
                ->validate()
                    ->ifTrue(static fn (array $v): bool => $v['low'] > $v['medium'])
                    ->thenInvalid('cost_thresholds.low (%s) must not be greater than cost_thresholds.medium.')
                ->end()
            ->end()
            ->arrayNode('logging')
                ->addDefaultsIfNotSet()
                ->children()
                    ->booleanNode('enabled')
                        ->defaultFalse()
                        ->info('Log per-request LLM cost data via Monolog. Disabled by default — opt in explicitly.')
                    ->end()
                    ->scalarNode('channel')
                        ->defaultValue('ai')
                        ->info('Monolog channel name for LLM cost logs. Allows routing to a dedicated handler.')
                    ->end()
                ->end()
            ->end()
            ->arrayNode('dynamic_pricing')
                ->addDefaultsIfNotSet()
                ->children()
                    ->booleanNode('enabled')
                        ->defaultTrue()
                        ->info('Fetch live model pricing from models.dev. Fills in pricing for models not in your config.')
                    ->end()
                    ->integerNode('ttl')
                        ->defaultValue(86400)
                        ->min(1)
                        ->max(604800)
                        ->info('How long to cache the models.dev response, in seconds. Default: 24h (86400). Minimum 1, maximum 7 days (604800). To disable dynamic pricing entirely use enabled: false.')
                    ->end()
                ->end()
            ->end()
            ->arrayNode('models')
                ->normalizeKeys(false)
                ->useAttributeAsKey('model_id')
                ->arrayPrototype()
                    ->children()
                        ->scalarNode('display_name')
                            ->isRequired()
                        ->end()
                        ->scalarNode('provider')
                            ->isRequired()
                        ->end()
                        ->floatNode('input_price_per_million')
                            ->isRequired()
                            ->min(0)
                            ->info('Price in USD per 1 million input tokens.')
                        ->end()
                        ->floatNode('output_price_per_million')
                            ->isRequired()
                            ->min(0)
                            ->info('Price in USD per 1 million output tokens.')
                        ->end()
                        ->floatNode('cached_input_price_per_million')
                            ->defaultNull()
                            ->min(0)
                            ->info('Price for cached input tokens. Falls back to input_price_per_million if not set.')
                        ->end()
                        ->floatNode('thinking_price_per_million')
                            ->defaultNull()
                            ->min(0)
                            ->info('Price for thinking/reasoning tokens. Not counted if not set.')
                        ->end()
                    ->end()
                ->end()
            ->end()
        ->end();
};
